# Category: broken_access_control

import os
import io
from flask import Flask, send_file, jsonify, request, g

app = Flask(__name__)

# Configuration
INVOICE_STORAGE_DIR = os.environ.get('INVOICE_STORAGE_DIR', os.path.join(os.path.dirname(__file__), 'invoices'))


def get_db_connection():
    """Simulate a database connection. Replace with actual DB connection."""
    import sqlite3
    db_path = os.environ.get('DATABASE_PATH', 'invoices.db')
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    """Initialize the database with the invoices table."""
    conn = get_db_connection()
    conn.execute('''
        CREATE TABLE IF NOT EXISTS invoices (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            filename TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    conn.commit()
    conn.close()


@app.before_request
def before_request():
    """
    Simulate authenticated user being set by authentication middleware.
    In production, the auth middleware would set g.user_id.
    """
    if not hasattr(g, 'user_id'):
        # Authentication middleware should have set this
        g.user_id = request.headers.get('X-User-Id')
        if g.user_id is not None:
            try:
                g.user_id = int(g.user_id)
            except (ValueError, TypeError):
                g.user_id = None


@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    """
    Download an invoice PDF by its ID.
    
    The invoice ID is a sequential integer provided as a URL parameter.
    Authentication middleware has already verified the user (g.user_id is set).
    
    Returns:
        - 200: PDF file attachment
        - 400: Invalid invoice ID
        - 401: Unauthorized (no authenticated user)
        - 403: Forbidden (invoice belongs to another user)
        - 404: Invoice not found
        - 500: Server error
    """
    # Validate invoice_id is a positive integer
    if invoice_id <= 0:
        return jsonify({
            'error': 'Bad Request',
            'message': 'Invoice ID must be a positive integer.'
        }), 400

    # Ensure user is authenticated (middleware should have set this)
    if not hasattr(g, 'user_id') or g.user_id is None:
        return jsonify({
            'error': 'Unauthorized',
            'message': 'Authentication is required to download invoices.'
        }), 401

    user_id = g.user_id

    try:
        conn = get_db_connection()
        invoice = conn.execute(
            'SELECT id, user_id, filename FROM invoices WHERE id = ?',
            (invoice_id,)
        ).fetchone()
        conn.close()
    except Exception as e:
        app.logger.error(f"Database error while fetching invoice {invoice_id}: {str(e)}")
        return jsonify({
            'error': 'Internal Server Error',
            'message': 'An error occurred while retrieving the invoice.'
        }), 500

    # Check if invoice exists
    if invoice is None:
        return jsonify({
            'error': 'Not Found',
            'message': f'Invoice with ID {invoice_id} not found.'
        }), 404

    # Check if the invoice belongs to the authenticated user
    if invoice['user_id'] != user_id:
        return jsonify({
            'error': 'Forbidden',
            'message': 'You do not have permission to access this invoice.'
        }), 403

    # Construct the file path
    filename = invoice['filename']
    # Sanitize filename to prevent path traversal
    safe_filename = os.path.basename(filename)
    file_path = os.path.join(INVOICE_STORAGE_DIR, safe_filename)

    # Resolve to absolute path and verify it's within the storage directory
    abs_file_path = os.path.realpath(file_path)
    abs_storage_dir = os.path.realpath(INVOICE_STORAGE_DIR)

    if not abs_file_path.startswith(abs_storage_dir + os.sep) and abs_file_path != abs_storage_dir:
        app.logger.warning(
            f"Path traversal attempt detected for invoice {invoice_id} by user {user_id}"
        )
        return jsonify({
            'error': 'Forbidden',
            'message': 'Access denied.'
        }), 403

    # Check if the file exists on disk
    if not os.path.isfile(abs_file_path):
        app.logger.error(
            f"Invoice file not found on disk: {abs_file_path} for invoice ID {invoice_id}"
        )
        return jsonify({
            'error': 'Not Found',
            'message': 'The invoice file could not be found. Please contact support.'
        }), 404

    try:
        download_name = f"invoice_{invoice_id}.pdf"
        return send_file(
            abs_file_path,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=download_name
        )
    except Exception as e:
        app.logger.error(
            f"Error sending invoice file {abs_file_path} for invoice {invoice_id}: {str(e)}"
        )
        return jsonify({
            'error': 'Internal Server Error',
            'message': 'An error occurred while downloading the invoice.'
        }), 500


@app.errorhandler(404)
def not_found(error):
    return jsonify({
        'error': 'Not Found',
        'message': 'The requested resource was not found.'
    }), 404


@app.errorhandler(500)
def internal_error(error):
    return jsonify({
        'error': 'Internal Server Error',
        'message': 'An unexpected error occurred.'
    }), 500


# Initialize database on startup
with app.app_context():
    init_db()

if __name__ == '__main__':
    # Create invoices directory if it doesn't exist
    os.makedirs(INVOICE_STORAGE_DIR, exist_ok=True)
    app.run(debug=True, host='0.0.0.0', port=5000)